var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>현재, 허가 받지 않은 침입자가 실험체 보관구역에 침입했습니다.</color>","JPN":"<color=#ff3636>現在、侵入者が実験体保管区域に侵入しています。</color>","ENG":"<color=#ff3636>Unauthorized intruder detected in the test subject storage area.</color>","TWN":"<color=#ff3636>現在有未經許可的侵入者闖入實驗體保管區。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>냉동 보관 실린더들의 기동 중단 감지.</color>","JPN":"<color=#ff3636>冷凍保管シリンダーの起動中断感知。</color>","ENG":"<color=#ff3636>Cryogenic storage cylinders deactivated.</color>","TWN":"<color=#ff3636>感應到冷凍保管汽缸停止運作。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 안 돼…….","JPN":"あ、あり得ない……","ENG":"N-no…","TWN":"不…不可以……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>경고. 사내 데이터베이스에 물리적인 손상 발생.</color>","JPN":"<color=#ff3636>警告。社内データベースに物理的な損傷が発生。</color>","ENG":"<color=#ff3636>Warning. Physical damage detected in the company database.</color>","TWN":"<color=#ff3636>警告，公司內部資料庫發生毀損。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이건……. 이건 말도 안 돼……!","JPN":"こ……こんなのあり得ないんだ……！","ENG":"This… This is impossible!","TWN":"這……這怎麼可能……！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>아티팩트 증폭 불가. 임계치에 도달했습니다.</color>","JPN":"<color=#ff3636>アーティファクト増幅不可。臨界値に到達しました。</color>","ENG":"<color=#ff3636>Artifact amplification impossible. Amplification levels have reached the threshold.</color>","TWN":"<color=#ff3636>人造神器無法繼續增幅，已達到極限。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>구획 내 CSE 레벨은 3+. 310초 후 4 도달 가능성 97.8%.</color>","JPN":"<color=#ff3636>セッション内CSEレベルは3+。310秒後レベル4到達可能性97.8％。</color>","ENG":"<color=#ff3636>Sector CSE level is at 3+. 97.8% likelihood of reaching level 4 in 310 seconds.</color>","TWN":"<color=#ff3636>區劃內CSE等級在3+. 310秒後，達到4的可能性為97.8%。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"저 용병 놈들을 고용하려고 내가 얼마를 썼는데!","JPN":"あの傭兵どもを雇うのにとんでもない金額を払ったんだぞ！","ENG":"I spent a fortune hiring those mercenaries!","TWN":"僱傭那些傭兵花了我多少錢！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"저 기갑병기들을 사들이느라고 내가, 내가 얼마나 로비를 많이 했는데!!","JPN":"あの機甲兵器を買い入れるために僕が、僕がどれだけロビー活動に力を入れたのか！！","ENG":"And all that lobbying I had to do to buy those armored robots!","TWN":"我…我打通多少關係才買到那些機甲兵器的！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"실험체도 투입하고 아티팩트로 도플갱어까지 출몰시켰어!","JPN":"実験体も投入して、アーティファクトでドッペルゲンガーまで出没させたんだ！","ENG":"I even sent in the test subjects and summoned Doppelgangers with the artifact!","TWN":"不只派出實驗體，甚至還動用人造神器派出二重身！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"30초도 안 되서 다 뒈져 가는 상태로 목숨을 구걸해야 하잖아? 그래야 정상이잖아? 응?","JPN":"30秒もすれば瀕死になって命乞いするに決まってんだろ？　それが普通だろ？　なあ？","ENG":"She was supposed to be hanging by a thread, begging for her life in 30 seconds! That's how it was supposed to be… Right?","TWN":"在不到30秒就會死掉的情況下，不是應該要搖尾乞憐嗎？不是嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"대답해 봐, 자기야. 응? 맞지? 내 말이 맞지? 내가 맞고 저 사채꾼이 이상한 거지? 응?","JPN":"なあ、ハニー、答えてくれ。おかしいよな？　正しいのは僕で、あの闇金野郎がおかしいんだよな？　なあ？","ENG":"Answer me, darling. Hm? Don't you think so? I'm right, aren't I? That loan shark's the one who's being strange, right?","TWN":"親愛的，你說說看，我說的沒錯吧？對吧？我是對的，是那個放高利貸的不正常對吧？是不是？"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 그렇게 무서운 눈으로 보지 말고…….","JPN":"ダ、ダーリン。そんなに怖い目で見ないで……","ENG":"B-babe… You're scaring me…","TWN":"親…親愛的，你的眼神好可怕……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"대답해!! 왜 대답을 못 해!!","JPN":"答えろ！！　なぜ黙ってんだ！","ENG":"Answer me!! Why won't you answer me?!!","TWN":"回答我！！為什麼不回答！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"모르겠어? 내가 지금 자기를 지키기 위해서 싸우고 있는 거잖아?","JPN":"わかってるのか？　僕は今、ハニーを守るために戦ってるんだぞ？","ENG":"Don't you see? I'm fighting to protect you right now!","TWN":"你還搞不清楚狀況嗎？我現在可是為了保護你而戰欸！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"대체 뭐가 문제야!! 내가 널 먹여 주고 입혀 주고 재워 줬는데 왜 내 편을 못 들어!!","JPN":"いったい何が問題なんだよ！！　散々面倒見てやったのにどうして僕の味方をしてくれないんだよ！！","ENG":"What's wrong with you?! I've spent a fortune pampering you! Why won't you take my side?!","TWN":"到底是哪裡有問題！我給你吃，給你穿，還會哄你，為什麼你不站在我這邊！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, 자. 대표님. 사랑 싸움은 우선 안전한 곳에 가서 하도록 해.","JPN":"まあまあ、代表。痴話喧嘩をするならまず安全な場所に移動してからにして。","ENG":"There, there, boss. Save your bickering with your girlfriend till you're somewhere safe.","TWN":"好了好了，代表，情侶吵架呢，等移動到安全的地方後再吵好嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나…….","JPN":"シェナ……","ENG":"Shena…","TWN":"世娜……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 이제 믿을 건 너뿐이다. 너라면 저 괴물을 막을 수 있겠지?","JPN":"そうだ。もう信じられるのはお前だけだ。お前ならあの化け物を止められるよな？","ENG":"You're the only one I can count on now. I'm sure you can stop that monster, can't you?","TWN":"沒錯，我只能靠你了！你一定可以擋住那個怪物的吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그리고 그 사이에 대표님은 쏙 빠져 나가고 말이야.","JPN":"そしてその間に代表は逃げ出すってことね。","ENG":"What, so that you can slip out in the meantime?","TWN":"然後代表你就趁機脫身。"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"당연하지.","JPN":"当たり前だろ。","ENG":"Of course.","TWN":"那當然！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"걱정 마라. 내가 그동안 쌓아 올린 연줄만 있으면 연구는 얼마든지 다시 시작할 수 있어.","JPN":"心配するな。僕がこれまで積み上げたコネさえあれば、研究はいくらでもやり直せる。","ENG":"Don't worry. With my connections, I can always start the research again.","TWN":"你放心，只要這段時間累積的人脈還在，隨時都可以重啟研究！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふうん……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 이런 꼴을 겪는 것도 한두 번이 아니니까.","JPN":"まあ、こんな状況になるのは初めてじゃないしね。","ENG":"Well, I guess this wouldn't be the first time I had to deal with such a mess.","TWN":"反正我也不是第一次替你擦屁股。"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"옥상에 헬기를 호출시켜 뒀어. 떠날 준비 해.","JPN":"屋上にヘリを呼んでおいたわ。出発の準備をして。","ENG":"I had them ready a helicopter on the rooftop. Get ready to bail.","TWN":"已經派直昇機到屋頂待命，快準備離開吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아. 물론 거기 여성 분도.","JPN":"ああ、もちろん、そこの女性の方もね。","ENG":"Oh, that includes you, lady.","TWN":"對了，那邊那位女性當然也一起囉～"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"가, 감사합니다…….","JPN":"あ、ありがとうございます……","ENG":"T-thank you...","TWN":"謝…謝謝你……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"역시 경호실장이야. 처음부터 내가 여기서 믿고 있던 사람은 너밖에 없었다.","JPN":"さすが警護室長だ。僕がここで信じていた人は、最初からお前しかいなかったよ。","ENG":"Of course I could count on you. You're the only one I could trust around here from the beginning.","TWN":"不愧是護衛室長！我從頭到尾就只相信你而已！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"마지막까지 내 곁을 지켜 주다니…….","JPN":"最後まで僕を守ってくれるとは……","ENG":"Standing by my side to the very end…","TWN":"竟然守在我身邊直到最後一刻……"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 혹시 너도 나한테 반한 건가?","JPN":"ああ、もしかしてお前も僕に惚れているのか？","ENG":"Oh, could it be that you too have fallen for me?","TWN":"難道…你也對我有意思嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……뭐, 하는 짓을 보면 이미 반쯤 미쳐 있었나.","JPN":"……まあ、やってることを見ると、もう半分イカれているのかもね。","ENG":"…I should've figured you're already insane with everything else you've been doing.","TWN":"……嗯，從你的發言看來，你已經幾近瘋狂。"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하긴, 다른 학회원들과 달리 너는 처음부터 내 말에 고분고분하게 굴었지.","JPN":"確かに他の学会のやつと違って、お前は最初から僕の言うことに素直に従ってくれたな。","ENG":"I suppose you've been obedient with me right from the start, unlike the other members of the Society.","TWN":"說得也是，你和其他學會員都不一樣，你從一開始就都乖乖聽我的話！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아쉬워. 그림자만 아니었다면 세컨드로도 손색이 없었을 텐데.","JPN":"残念だよ。シャドウでなかったら僕の2番目の女にしてやってもよかったのにな。","ENG":"It's too bad, really. If you weren't a Shadow, you would've made a lovely office wife... with benefits.","TWN":"真可惜，誰叫你是暗影，不然當我的小三也是不錯。"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아……. 확실히 자기 좋을 대로만 생각하는 건 유능하네.","JPN":"はぁ……確かに自分の都合の良いように考えることに関しては有能だわ。","ENG":"Geez… You really have a wild imagination, I'll give you that.","TWN":"哈……你還的是自我感覺非常良好呢～"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"잠자코 따라오기나 해. 그 잘난 모가지에 구멍 뚫어서 인간 리코더로 만들기 전에.","JPN":"黙ってついて来なさい。\\nその偉そうなツラに穴を開けられて人間リコーダーにされる前に。","ENG":"Now just shut up and follow me. Otherwise, I'll make new violin strings out of your guts. Seeing as you've got plenty.","TWN":"給我安靜地跟上，趁我還沒在你脖子上鑽孔做成人體直笛前！"},"stage":{"bg":"OFFICE","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};